// Parse the JSON that `reminders run --send --json` printed on stdout, and
// gate: only proceed to approval if a batch was actually staged.
const item = $input.first().json;
const raw = item.stdout || '';
let data;
try {
  data = JSON.parse(raw);
} catch (err) {
  throw new Error('Could not parse `reminders --json` output. Got: ' + raw);
}
if (data.error) {
  throw new Error('reminders refused: ' + (data.message || data.error));
}
if (!data.count || data.count === 0) {
  return []; // nothing due -> stop here, no approval needed
}
return [{ json: data }];

// Build a human-readable approval request + the resume link. Wire the node
// AFTER this one to your Slack/Email and send `approvalMessage`.
const data = $input.first().json;
const lines = (data.reminders || []).map(function (r) {
  return '  - ' + r.invoice_id + '  ' + r.stage + '  ' + r.currency + ' ' + r.amount + '  -> ' + r.to_email;
});
return [{
  json: Object.assign({}, data, {
    approvalUrl: $execution.resumeUrl,
    approvalMessage:
      'Invoice reminders ready to send (batch ' + data.batch_id + ', ' + data.count + ' reminder(s)):\n' +
      lines.join('\n') +
      '\n\nApprove (this sends the emails): ' + $execution.resumeUrl
  })
}];

// Parse the result of `reminders approve --json` for the execution log.
const item = $input.first().json;
let result;
try { result = JSON.parse(item.stdout || '{}'); } catch (e) { result = { parseError: item.stdout }; }
return [{ json: Object.assign({ ok: !result.error }, result) }];
